import api from './api';

class AuthService {
    async registerWithFingerprint(username, email, password, healthRecordId) {
        try {
            const response = await api.post('/auth/register', {
                username,
                email,
                password,
                healthRecordId
            });
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async loginWithFingerprint(username) {
        try {
            const response = await api.post('/auth/login/fingerprint', { username });
            if (response.data.token) {
                localStorage.setItem('authToken', response.data.token);
                localStorage.setItem('user', JSON.stringify(response.data.user));
            }
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async loginWithPassword(username, password) {
        try {
            const response = await api.post('/auth/login/password', { username, password });
            if (response.data.token) {
                localStorage.setItem('authToken', response.data.token);
                localStorage.setItem('user', JSON.stringify(response.data.user));
            }
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    async verifyToken() {
        try {
            const response = await api.get('/auth/verify');
            return response.data;
        } catch (error) {
            throw this.handleError(error);
        }
    }

    logout() {
        localStorage.removeItem('authToken');
        localStorage.removeItem('user');
    }

    getCurrentUser() {
        const userStr = localStorage.getItem('user');
        return userStr ? JSON.parse(userStr) : null;
    }

    handleError(error) {
        if (error.response) {
            return new Error(error.response.data.error || 'Server error');
        } else if (error.request) {
            return new Error('No response from server');
        } else {
            return new Error('Request failed');
        }
    }
}

const authService = new AuthService();
export default authService;
